import anthropic
import json

client = anthropic.Anthropic()

PLANNING_SYSTEM = """
You are a research assistant. Before taking any action, write a brief plan.

Thought format:
  Plan: <ordered list of steps needed to answer the question>
  Current step: <which step from the plan you are executing now>
  Reasoning: <why this step, and what you expect to learn from it>

Tools:
- search(query): search for information
- task_complete(answer): call when you have a complete answer

Rules:
- Write the Plan on the first iteration only
- Update the Plan only if an observation reveals that the original plan was wrong
- Call task_complete as soon as the answer is complete — do not over-research
"""

def search(query: str) -> str:
    # Stub — replace with a real search API
    stubs = {
        "apple revenue 2023": '{"revenue_usd_billions": 383.3, "year": 2023}',
        "microsoft revenue 2023": '{"revenue_usd_billions": 211.9, "year": 2023}',
    }
    for key, val in stubs.items():
        if key in query.lower():
            return val
    return json.dumps({"results": [], "message": "No results"})

TOOLS = [
    {"name": "search", "description": "Search for information.",
     "input_schema": {"type": "object", "properties": {"query": {"type": "string"}}, "required": ["query"]}},
    {"name": "task_complete", "description": "Submit the final answer.",
     "input_schema": {"type": "object", "properties": {"answer": {"type": "string"}}, "required": ["answer"]}},
]
DISPATCH = {"search": search}

def run_planning_agent(user_message: str, max_iterations: int = 10) -> dict:
    messages = [{"role": "user", "content": user_message}]

    for iteration in range(1, max_iterations + 1):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            system=PLANNING_SYSTEM,
            tools=TOOLS,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": resp.content})
        tool_calls = [b for b in resp.content if b.type == "tool_use"]

        for block in tool_calls:
            if block.name == "task_complete":
                return {"status": "complete", "answer": block.input["answer"], "iterations": iteration}

        if not tool_calls:
            text = next((b.text for b in resp.content if b.type == "text"), "")
            return {"status": "stuck", "partial": text, "iterations": iteration}

        results = []
        for block in tool_calls:
            fn = DISPATCH.get(block.name)
            result = fn(**block.input) if fn else json.dumps({"error": "Unknown"})
            results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})
        messages.append({"role": "user", "content": results})

    return {"status": "max_iterations", "iterations": max_iterations}

outcome = run_planning_agent("Compare the 2023 annual revenue of Apple and Microsoft.")
print(outcome)
# Plan (in Thought): 1. Search Apple revenue 2023. 2. Search Microsoft revenue 2023. 3. Compare.
# Iterations: 3 (search Apple → search Microsoft → task_complete)
